/**
 * Routes: WhatsApp config, contacts, routing, groups
 */
const express = require('express');
const fs = require('fs');
const path = require('path');
const os = require('os');
const router = express.Router();
const { GATEWAYS, readGatewayConfig, writeGatewayConfig } = require('../services/gateway-config');

const WA_ROUTING_PATH = path.join(os.homedir(), '.openclaw', 'whatsapp-routing.json');

function readWaRouting() {
  try {
    if (fs.existsSync(WA_ROUTING_PATH)) return JSON.parse(fs.readFileSync(WA_ROUTING_PATH, 'utf8'));
  } catch (e) { /* ignore */ }
  return { contacts: {} };
}

function writeWaRouting(data) {
  fs.writeFileSync(WA_ROUTING_PATH, JSON.stringify(data, null, 2), 'utf8');
}

// Overview
router.get('/', (req, res) => {
  try {
    const result = [];
    for (const gw of GATEWAYS) {
      const config = readGatewayConfig(gw);
      if (!config) continue;
      const wa = config.channels?.whatsapp || {};
      result.push({
        gateway: { id: gw.id, label: gw.label, port: gw.port },
        enabled: wa.enabled || false, dmPolicy: wa.dmPolicy || 'deny',
        allowFrom: wa.allowFrom || [], groupPolicy: wa.groupPolicy || 'deny', allowGroups: wa.allowGroups || []
      });
    }
    const routing = readWaRouting();
    let groups = [];
    const groupsFile = path.join(os.homedir(), '.openclaw', 'workspace', 'memory', 'whatsapp-groups-directory.md');
    if (fs.existsSync(groupsFile)) {
      const content = fs.readFileSync(groupsFile, 'utf8');
      for (const line of content.split('\n')) {
        const match = line.match(/\|\s*(.+?)\s*\|\s*(\S+@g\.us)\s*\|/);
        if (match && match[1] !== 'Nom du groupe') groups.push({ name: match[1].trim(), jid: match[2].trim() });
      }
    }
    res.json({ gateways: result, routing: routing.contacts || {}, groups });
  } catch (e) {
    res.status(500).json({ error: 'Erreur WhatsApp config', details: e.message });
  }
});

// Add contact
router.post('/contacts', (req, res) => {
  const { phone, gatewayId, label } = req.body;
  if (!phone || !gatewayId) return res.status(400).json({ error: 'Num\u00e9ro et gateway sont requis' });
  const normalizedPhone = phone.startsWith('+') ? phone : '+' + phone;
  const gw = GATEWAYS.find(g => g.id === gatewayId);
  if (!gw) return res.status(400).json({ error: 'Gateway inconnue' });
  const config = readGatewayConfig(gw);
  if (!config) return res.status(500).json({ error: 'Config non lisible' });
  if (!config.channels) config.channels = {};
  if (!config.channels.whatsapp) config.channels.whatsapp = { enabled: true, dmPolicy: 'allowlist', allowFrom: [] };
  if (!config.channels.whatsapp.allowFrom) config.channels.whatsapp.allowFrom = [];
  if (config.channels.whatsapp.allowFrom.includes(normalizedPhone)) return res.status(409).json({ error: 'Ce num\u00e9ro est d\u00e9j\u00e0 dans la liste' });
  config.channels.whatsapp.allowFrom.push(normalizedPhone);
  writeGatewayConfig(gw, config);
  if (label) {
    const routing = readWaRouting();
    if (!routing.contacts) routing.contacts = {};
    if (!routing.contacts[normalizedPhone]) routing.contacts[normalizedPhone] = {};
    routing.contacts[normalizedPhone].label = label;
    writeWaRouting(routing);
  }
  res.json({ success: true, message: `Contact ${normalizedPhone} ajout\u00e9 \u00e0 ${gw.label}`, restartNeeded: true, gateway: gw.id });
});

// Remove contact
router.delete('/contacts/:phone', (req, res) => {
  const phone = decodeURIComponent(req.params.phone);
  const { gatewayId } = req.query;
  if (!gatewayId) return res.status(400).json({ error: 'gatewayId requis en query param' });
  const gw = GATEWAYS.find(g => g.id === gatewayId);
  if (!gw) return res.status(400).json({ error: 'Gateway inconnue' });
  const config = readGatewayConfig(gw);
  if (!config) return res.status(500).json({ error: 'Config non lisible' });
  const list = config.channels?.whatsapp?.allowFrom || [];
  const idx = list.indexOf(phone);
  if (idx === -1) return res.status(404).json({ error: 'Num\u00e9ro non trouv\u00e9 dans la liste' });
  list.splice(idx, 1);
  writeGatewayConfig(gw, config);
  res.json({ success: true, message: `Contact ${phone} retir\u00e9 de ${gw.label}`, restartNeeded: true, gateway: gw.id });
});

// Routing
router.get('/routing', (req, res) => { res.json(readWaRouting()); });

router.post('/routing', (req, res) => {
  const { phone, agentId, label } = req.body;
  if (!phone) return res.status(400).json({ error: 'Num\u00e9ro requis' });
  const normalizedPhone = phone.startsWith('+') ? phone : '+' + phone;
  const routing = readWaRouting();
  if (!routing.contacts) routing.contacts = {};
  if (agentId) {
    routing.contacts[normalizedPhone] = {
      agentId, label: label || routing.contacts[normalizedPhone]?.label || '',
      updatedAt: new Date().toISOString()
    };
  } else {
    if (routing.contacts[normalizedPhone]) delete routing.contacts[normalizedPhone].agentId;
  }
  writeWaRouting(routing);
  res.json({ success: true, message: `Routing ${normalizedPhone} \u2192 ${agentId || 'aucun'}` });
});

// Add group
router.post('/groups', (req, res) => {
  const { name, jid, gatewayId } = req.body;
  if (!name || !jid) return res.status(400).json({ error: 'Nom et JID requis' });
  const groupsFile = path.join(os.homedir(), '.openclaw', 'workspace', 'memory', 'whatsapp-groups-directory.md');
  if (fs.existsSync(groupsFile)) {
    let content = fs.readFileSync(groupsFile, 'utf8');
    if (content.includes(jid)) return res.status(409).json({ error: 'Ce groupe (JID) existe d\u00e9j\u00e0' });
    const insertBefore = '## Comment utiliser';
    if (content.includes(insertBefore)) content = content.replace(insertBefore, `| ${name} | ${jid} |\n\n${insertBefore}`);
    else content += `\n| ${name} | ${jid} |\n`;
    fs.writeFileSync(groupsFile, content, 'utf8');
  }
  if (gatewayId) {
    const gw = GATEWAYS.find(g => g.id === gatewayId);
    if (gw) {
      const config = readGatewayConfig(gw);
      if (config) {
        if (!config.channels) config.channels = {};
        if (!config.channels.whatsapp) config.channels.whatsapp = {};
        if (!config.channels.whatsapp.allowGroups) config.channels.whatsapp.allowGroups = [];
        if (!config.channels.whatsapp.allowGroups.includes(jid)) {
          config.channels.whatsapp.allowGroups.push(jid);
          writeGatewayConfig(gw, config);
        }
      }
    }
  }
  res.json({ success: true, message: `Groupe "${name}" ajout\u00e9` });
});

module.exports = router;

