/**
 * Gateway configuration management — read/write with OAuth protection
 */
const fs = require('fs');
const path = require('path');
const os = require('os');
const { stripMd } = require('./helpers');

const GATEWAYS = [
  {
    id: 'mybotia',
    label: 'MyBotIA',
    configPath: path.join(os.homedir(), '.openclaw', 'openclaw.json'),
    stateDir: path.join(os.homedir(), '.openclaw'),
    port: 18789,
    mode: 'host',
    logFile: '/tmp/mybotia-gateway.log',
    restartCmd: 'pkill -f "openclaw gateway --port 18789" 2>/dev/null; sleep 2; nohup openclaw gateway --port 18789 > /tmp/mybotia-gateway.log 2>&1 &'
  },
  {
    id: 'vlmedical',
    label: 'VL Medical',
    configPath: path.join(os.homedir(), '.openclaw-vlmedical', 'openclaw.json'),
    stateDir: path.join(os.homedir(), '.openclaw-vlmedical'),
    port: 18790,
    mode: 'host',
    logFile: '/tmp/vlmedical-gateway.log',
    restartCmd: 'pkill -f "openclaw.*gateway.*--port 18790" 2>/dev/null; sleep 2; OPENCLAW_CONFIG_PATH=/home/gilles/.openclaw-vlmedical/openclaw.json OPENCLAW_STATE_DIR=/home/gilles/.openclaw-vlmedical nohup openclaw gateway --port 18790 > /tmp/vlmedical-gateway.log 2>&1 &'
  },
  {
    id: 'test',
    label: 'Test (Brice)',
    configPath: path.join(os.homedir(), '.openclaw-test', 'openclaw.json'),
    stateDir: path.join(os.homedir(), '.openclaw-test'),
    port: 18794,
    mode: 'host',
    logFile: '/tmp/test-gateway.log',
    restartCmd: 'pkill -f "openclaw.*gateway.*--port 18794" 2>/dev/null; sleep 2; OPENCLAW_CONFIG_PATH=/home/gilles/.openclaw-test/openclaw.json OPENCLAW_STATE_DIR=/home/gilles/.openclaw-test nohup openclaw gateway --port 18794 > /tmp/test-gateway.log 2>&1 &'
  },
  {
    id: 'lucy-igh',
    label: 'Lucy (IGH)',
    configPath: path.join(os.homedir(), '.openclaw-lucy', 'openclaw.json'),
    stateDir: path.join(os.homedir(), '.openclaw-lucy'),
    port: 18795,
    mode: 'host',
    logFile: '/tmp/lucy-gateway.log',
    restartCmd: 'pkill -f "openclaw.*gateway.*--port 18795" 2>/dev/null; sleep 2; OPENCLAW_CONFIG_PATH=/home/gilles/.openclaw-lucy/openclaw.json OPENCLAW_STATE_DIR=/home/gilles/.openclaw-lucy nohup openclaw gateway --port 18795 > /tmp/lucy-gateway.log 2>&1 &'
  }
];

const TEMPLATE_DIR = path.join(os.homedir(), 'collaborateur-template');

// Avatars are now stored in each agent's IDENTITY.md (Avatar: field)
// No more hardcoded fallbacks

function readGatewayConfig(gw) {
  try {
    const raw = fs.readFileSync(gw.configPath, 'utf8');
    return JSON.parse(raw);
  } catch (e) {
    return null;
  }
}

function writeGatewayConfig(gw, config) {
  // SAFETY: Read current config and preserve ALL auth/credential sections
  const currentRaw = fs.readFileSync(gw.configPath, 'utf8');
  const current = JSON.parse(currentRaw);

  const PROTECTED_KEYS = ['auth', 'credentials', 'tokens', 'oauth', 'apiKeys'];
  for (const key of PROTECTED_KEYS) {
    if (current[key] !== undefined) {
      config[key] = current[key];
    }
  }
  // Protect nested auth in channels
  if (current.channels) {
    if (!config.channels) config.channels = {};
    for (const [chName, chConf] of Object.entries(current.channels)) {
      if (!config.channels[chName]) config.channels[chName] = {};
      for (const authKey of ['auth', 'token', 'credentials', 'apiKey', 'secret', 'botToken']) {
        if (chConf[authKey] !== undefined) {
          config.channels[chName][authKey] = chConf[authKey];
        }
      }
    }
  }
  // Protect agent-level auth tokens
  if (config.agents?.list && current.agents?.list) {
    for (const agent of config.agents.list) {
      const orig = current.agents.list.find(a => a.id === agent.id);
      if (orig) {
        for (const key of ['auth', 'token', 'credentials', 'apiKey']) {
          if (orig[key] !== undefined) agent[key] = orig[key];
        }
      }
    }
  }

  const bakPath = gw.configPath + '.bak-' + new Date().toISOString().replace(/[:.]/g, '-');
  fs.copyFileSync(gw.configPath, bakPath);
  fs.writeFileSync(gw.configPath, JSON.stringify(config, null, 2), 'utf8');
}

function readAgentIdentity(wsPath, agentId) {
  const identityPath = path.join(wsPath, 'IDENTITY.md');
  if (!fs.existsSync(identityPath)) return null;
  const content = fs.readFileSync(identityPath, 'utf8');
  const nameMatch = content.match(/Nom\s*[:|]\s*(.+)/i);
  const roleMatch = content.match(/Rôle\s*[:|]\s*(.+)/i);
  const emojiMatch = content.match(/Emoji\s*[:|]\s*(.+)/i);
  const avatarMatch = content.match(/Avatar\s*\**\s*[:|]\s*\**\s*(https?:\/\/\S+)/i);
  return {
    displayName: nameMatch ? stripMd(nameMatch[1]) : null,
    role: roleMatch ? stripMd(roleMatch[1]) : null,
    emoji: emojiMatch ? stripMd(emojiMatch[1]) : null,
    avatar: avatarMatch ? avatarMatch[1].trim() : null
  };
}

function getGatewayDashboardUrl(gw) {
  const config = readGatewayConfig(gw);
  if (!config) return null;
  const token = config.gateway?.auth?.token;
  if (!token) return null;
  return `http://127.0.0.1:${gw.port}/#token=${token}`;
}

function findAgentGateway(agentId, gatewayId) {
  for (const gw of GATEWAYS) {
    if (gatewayId && gw.id !== gatewayId) continue;
    const config = readGatewayConfig(gw);
    if (!config) continue;
    const agents = config.agents?.list || [];
    const agent = agents.find(a => a.id === agentId);
    if (agent) return { gw, config, agent, agentIndex: agents.indexOf(agent) };
  }
  return null;
}

module.exports = {
  GATEWAYS,
  TEMPLATE_DIR,
  readGatewayConfig,
  writeGatewayConfig,
  readAgentIdentity,
  findAgentGateway,
  getGatewayDashboardUrl
};

