// ── WhatsApp Protocols ──

const PROFILE_DEFAULTS = {
  CLIENT:  { reactivity: 'TOUJOURS',     tone: 'Pro formel',       pricing_talk: 'INTERDIT', role: 'Assistante projet' },
  DEMO:    { reactivity: 'TOUJOURS',     tone: 'Pro décontracté',  pricing_talk: 'INTERDIT', role: 'Démonstration IA' },
  PERSO:   { reactivity: 'SUR_DEMANDE',  tone: 'Amical',           pricing_talk: 'INTERDIT', role: 'Aide ponctuelle' },
  INTERNE: { reactivity: 'TOUJOURS',     tone: 'Direct',           pricing_talk: 'LIBRE',    role: 'Équipe interne' }
};

const PROFILE_COLORS = { CLIENT: '--blue', DEMO: '--yellow', PERSO: '--muted', INTERNE: '--green' };
const REACTIVITY_COLORS = { TOUJOURS: '--green', SUR_DEMANDE: '--yellow', SILENCIEUX: '--red' };

if (!STATE.waProtocols) STATE.waProtocols = { list: [], health: {}, loading: false };

function renderWaProtocols() {
  let html = '<div id="wa-protocols-content"><div style="text-align:center;padding:40px;color:var(--muted);">Chargement...</div></div>';
  loadWaProtocols();
  return html;
}

async function loadWaProtocols() {
  if (STATE.waProtocols.loading) return;
  STATE.waProtocols.loading = true;
  try {
    const data = await api('/api/whatsapp/protocols?all=true');
    STATE.waProtocols.list = data.protocols || [];
    STATE.waProtocols.health = data.health || {};
    renderWaProtocolsContent();
  } catch (e) {
    const el = document.getElementById('wa-protocols-content');
    if (el) el.innerHTML = '<div style="color:var(--red);padding:20px;">Erreur: ' + esc(e.message) + '</div>';
  } finally {
    STATE.waProtocols.loading = false;
  }
}

function renderWaProtocolsContent() {
  const el = document.getElementById('wa-protocols-content');
  if (!el) return;

  const protocols = STATE.waProtocols.list;
  const h = STATE.waProtocols.health;
  let html = '';

  // Health indicator
  if (h.synced === true) {
    html += '<div style="background:rgba(34,197,94,0.1);border:1px solid rgba(34,197,94,0.3);border-radius:10px;padding:10px 16px;margin-bottom:16px;font-size:12px;color:var(--green);">';
    html += 'Fichier synchronis\u00e9 — derni\u00e8re g\u00e9n\u00e9ration : ' + esc(h.file_date || '?') + ' — ' + h.db_count + ' groupes';
    html += '</div>';
  } else {
    html += '<div style="background:rgba(245,158,11,0.1);border:1px solid rgba(245,158,11,0.3);border-radius:10px;padding:10px 16px;margin-bottom:16px;font-size:12px;color:var(--yellow);">';
    html += 'Fichier d\u00e9synchronis\u00e9 — ' + (h.db_count || 0) + ' groupes en base vs ' + (h.file_count || 0) + ' dans le fichier';
    html += ' <button class="btn btn-ghost btn-sm" onclick="forceWaSync()" style="margin-left:10px;font-size:11px;">Forcer la sync</button>';
    html += '</div>';
  }

  // KPIs
  const active = protocols.filter(p => p.active);
  const archived = protocols.filter(p => !p.active);
  const byProfile = {};
  active.forEach(p => { byProfile[p.profile] = (byProfile[p.profile] || 0) + 1; });

  html += '<div class="kpi-grid" style="margin-bottom:16px;">';
  html += waKpi(active.length, 'Actifs', '--green');
  html += waKpi(archived.length, 'Archiv\u00e9s', '--muted');
  html += waKpi(byProfile.CLIENT || 0, 'Clients', '--blue');
  html += waKpi(byProfile.DEMO || 0, 'D\u00e9mo', '--yellow');
  html += waKpi(byProfile.PERSO || 0, 'Perso', '--muted');
  html += waKpi(byProfile.INTERNE || 0, 'Interne', '--green');
  html += '</div>';

  // Toolbar
  html += '<div style="display:flex;gap:10px;align-items:center;margin-bottom:16px;flex-wrap:wrap;">';
  html += '<button class="btn btn-ghost btn-sm" onclick="forceWaSync()" style="font-size:11px;">Forcer la sync</button>';
  html += '<button class="btn btn-ghost btn-sm" onclick="loadWaProtocols()" style="font-size:11px;">Actualiser</button>';
  html += '<div style="flex:1;"></div>';
  html += '<button class="btn btn-primary" onclick="openWaProtocolModal()">+ Nouveau protocole</button>';
  html += '</div>';

  // Table
  html += '<div class="table-card"><table class="table"><thead><tr>';
  html += '<th>Groupe</th><th>JID</th><th>Profil</th><th>R\u00e9activit\u00e9</th><th>Ton</th><th>Tarifs</th><th>Client li\u00e9</th><th>Statut</th><th></th>';
  html += '</tr></thead><tbody>';

  if (!protocols.length) {
    html += '<tr><td colspan="9" style="text-align:center;color:var(--muted);padding:30px;">Aucun protocole configur\u00e9</td></tr>';
  }

  for (const p of protocols) {
    const profColor = PROFILE_COLORS[p.profile] || '--muted';
    const reactColor = REACTIVITY_COLORS[p.reactivity] || '--muted';
    const opacity = p.active ? '1' : '0.5';

    html += '<tr style="opacity:' + opacity + ';cursor:pointer;" onclick="openWaProtocolModal(' + p.id + ')">';
    html += '<td style="font-weight:500;">' + esc(p.group_name) + '</td>';
    html += '<td style="font-family:monospace;font-size:11px;">' + esc(p.jid.substring(0, 12)) + '... ';
    html += '<button class="btn-icon" onclick="event.stopPropagation();copyJid(\'' + esc(p.jid) + '\')" title="Copier JID">';
    html += '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>';
    html += '</button></td>';
    html += '<td><span class="crm-badge" style="background:var(' + profColor + ');color:#fff;font-size:10px;padding:2px 8px;border-radius:6px;">' + esc(p.profile) + '</span></td>';
    html += '<td><span class="crm-badge" style="background:var(' + reactColor + ');color:#fff;font-size:10px;padding:2px 8px;border-radius:6px;">' + esc(p.reactivity) + '</span></td>';
    html += '<td>' + esc(p.tone || '—') + '</td>';
    html += '<td>' + esc(p.pricing_talk) + '</td>';
    html += '<td>' + esc(p.client_name || '—') + '</td>';
    html += '<td>' + (p.active ? '<span style="color:var(--green);">Actif</span>' : '<span style="color:var(--muted);">Archiv\u00e9</span>') + '</td>';
    html += '<td>';
    if (p.active) {
      html += '<button class="btn-icon" onclick="event.stopPropagation();archiveWaProtocol(' + p.id + ',\'' + esc(p.group_name) + '\')" title="Archiver"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg></button>';
    }
    html += '</td>';
    html += '</tr>';
  }

  html += '</tbody></table></div>';
  el.innerHTML = html;
}

function waKpi(val, label, color) {
  return '<div class="kpi-card"><div class="kpi-value" style="color:var(' + color + ');">' + val + '</div><div class="kpi-label">' + label + '</div></div>';
}

function copyJid(jid) {
  navigator.clipboard.writeText(jid).then(() => showToast('JID copié : ' + jid));
}

async function forceWaSync() {
  try {
    const res = await api('/api/whatsapp/protocols/sync-md', { method: 'POST' });
    showToast(res.message || 'Sync OK');
    loadWaProtocols();
  } catch (e) {
    showToast('Erreur sync: ' + e.message, 'error');
  }
}

async function archiveWaProtocol(id, name) {
  if (!confirm('Archiver le protocole "' + name + '" ?')) return;
  try {
    await api('/api/whatsapp/protocols/' + id, { method: 'DELETE' });
    showToast('Protocole archivé');
    loadWaProtocols();
  } catch (e) {
    showToast('Erreur: ' + e.message, 'error');
  }
}

// ── Modal ──

async function openWaProtocolModal(id) {
  let protocol = null;
  if (id) {
    try { protocol = await api('/api/whatsapp/protocols/' + id); }
    catch { showToast('Protocole introuvable', 'error'); return; }
  }

  // Load clients for dropdown
  let clients = [];
  try {
    const res = await api('/api/crm/clients');
    clients = res.clients || [];
  } catch { /* ok, no clients */ }

  const isEdit = !!protocol;
  const title = isEdit ? 'Modifier : ' + esc(protocol.group_name) : 'Nouveau protocole';

  let body = '';
  body += '<div class="form-row">';
  body += '<div class="form-group"><label class="form-label">Nom du groupe</label>';
  body += '<input class="form-input" id="wp-group-name" value="' + esc(protocol?.group_name || '') + '"></div>';
  body += '<div class="form-group"><label class="form-label">JID</label>';
  body += '<input class="form-input" id="wp-jid" value="' + esc(protocol?.jid || '') + '" placeholder="120363...@g.us"></div>';
  body += '</div>';

  body += '<div class="form-row">';
  body += '<div class="form-group"><label class="form-label">Profil</label>';
