    html += '</div>';
  } else {
    html += '<div style="background:rgba(245,158,11,0.1);border:1px solid rgba(245,158,11,0.3);border-radius:10px;padding:10px 16px;margin-bottom:16px;font-size:12px;color:var(--yellow);">';
    html += 'Fichier d\u00e9synchronis\u00e9 — ' + (h.db_count || 0) + ' groupes en base vs ' + (h.file_count || 0) + ' dans le fichier';
